CREATE TRIGGER LG_DTLINE_UPD_001_01 ON LG_001_01_DISTORDLINE
FOR UPDATE
AS
DECLARE @c_CompLine         SMALLINT
DECLARE @new_ItemRef        INT
DECLARE @new_VariantRef     INT
DECLARE @new_OrdLineRef     INT
DECLARE @new_DOrdDate       DATETIME
DECLARE @new_ShipAmount     FLOAT
DECLARE @new_RemAmount      FLOAT
DECLARE @new_UomRef         INT
DECLARE @new_SourceIndex    SMALLINT
DECLARE @new_DOrdStatus     INT
DECLARE @new_DOrdGoDate     DATETIME
DECLARE @new_DOrdRetDate    DATETIME
DECLARE @new_LineType       SMALLINT
DECLARE @new_uinfo1         FLOAT
DECLARE @new_uinfo2         FLOAT
DECLARE @old_ItemRef        INT
DECLARE @old_VariantRef     INT
DECLARE @old_OrdLineRef     INT
DECLARE @old_DOrdDate       DATETIME
DECLARE @old_ShipAmount     FLOAT
DECLARE @old_RemAmount      FLOAT
DECLARE @old_UomRef         INT
DECLARE @old_SourceIndex    SMALLINT
DECLARE @old_DOrdStatus     INT
DECLARE @old_DOrdGoDate     DATETIME
DECLARE @old_DOrdRetDate    DATETIME
DECLARE @old_LineType       SMALLINT
DECLARE @old_uinfo1         FLOAT
DECLARE @old_uinfo2         FLOAT
SELECT @c_CompLine  = 7
SELECT @new_ItemRef = I.ITEMREF,
       @new_VariantRef = I.VARIANTREF,
       @new_OrdLineRef = I.ORDLINEREF,
       @new_DOrdDate = I.DATE_,
       @new_ShipAmount = I.SHIPAMOUNT,
       @new_RemAmount = I.REMAMOUNT,
       @new_UomRef = I.UOMREF,
       @new_SourceIndex = I.SOURCEINDEX,
       @new_DOrdStatus = I.DORDSTATUS,
       @new_DOrdGoDate = I.DORDGODATE,
       @new_DOrdRetDate = I.DORDRETURNDATE,
       @new_LineType = I.LINETYPE,
       @new_uinfo1   = I.UINFO1,
       @new_uinfo2   = I.UINFO2
FROM INSERTED I
SELECT @old_ItemRef = D.ITEMREF,
       @old_VariantRef = D.VARIANTREF,
       @old_OrdLineRef = D.ORDLINEREF,
       @old_DOrdDate = D.DATE_,
       @old_ShipAmount = D.SHIPAMOUNT,
       @old_RemAmount = D.REMAMOUNT,
       @old_UomRef = D.UOMREF,
       @old_SourceIndex = D.SOURCEINDEX,
       @old_DOrdStatus = D.DORDSTATUS,
       @old_DOrdGoDate = D.DORDGODATE,
       @old_DOrdRetDate = D.DORDRETURNDATE,
       @old_LineType = D.LINETYPE,
       @old_uinfo1   = D.UINFO1,
       @old_uinfo2   = D.UINFO2
FROM DELETED D
IF (@old_LineType <> @c_CompLine)
 EXECUTE LG_DTHANDLENUMBERS_001_01 -1, @old_ItemRef, @old_VariantRef, @old_OrdLineRef, @old_DOrdDate,
                                   @old_ShipAmount,  @old_RemAmount,  @old_UomRef,
                                   @old_SourceIndex, @old_DOrdStatus, @old_DOrdGoDate,
                                   @old_DOrdRetDate, @old_uinfo1, @old_uinfo2
IF (@new_LineType <> @c_CompLine)
 EXECUTE LG_DTHANDLENUMBERS_001_01 1, @new_ItemRef,  @new_VariantRef, @new_OrdLineRef, @new_DOrdDate,
                                   @new_ShipAmount,  @new_RemAmount,  @new_UomRef,
                                   @new_SourceIndex, @new_DOrdStatus, @new_DOrdGoDate,
                                   @new_DOrdRetDate, @new_uinfo1, @new_uinfo2
